const input = $input.first().json;
let parsed = {};
try { if (input.chatInput && input.chatInput.startsWith('{')) parsed = JSON.parse(input.chatInput); } catch(e) {}

let rawText = input.chatInput || '';
let detectedAction = null;
let cleanedText = rawText;
if (rawText.toLowerCase().startsWith('upsert:')) { detectedAction = 'upsert'; cleanedText = rawText.substring(7).trim(); }
else if (rawText.toLowerCase().startsWith('search:')) { detectedAction = 'search'; cleanedText = rawText.substring(7).trim(); }

let action = detectedAction || parsed.action || (input.action === 'sendMessage' ? 'search' : input.action) || 'search';
const query = parsed.query || cleanedText || '';
const namespace = parsed.namespace || input.namespace || 'default';
const source = parsed.source || input.source || 'manual';
const project = parsed.project || input.project || 'profit';
const content = parsed.content || cleanedText || query;

return [{ json: { action, query, namespace, source, project, content } }];

const query = $('Normalize Input').first().json.query;
const namespace = $('Normalize Input').first().json.namespace;
const hits = $('Pinecone → Search').first().json.result?.hits || $('Pinecone → Search').first().json.matches || [];
const answer = $input.first().json.content?.[0]?.text || 'No answer generated';

return [{ json: {
  status: 'completed',
  workflow: '12_pinecone_rag',
  action: 'search',
  query,
  namespace,
  results_count: hits.length,
  top_sources: hits.slice(0, 3).map(function(m) { return { score: m.score || m._score, source: (m.fields && m.fields.source) || (m.metadata && m.metadata.source) || 'unknown' }; }),
  answer,
  completedAt: new Date().toISOString()
} }];

const input = $('Normalize Input').first().json;
const upsertResult = $input.first().json;

return [{ json: {
  status: 'completed',
  workflow: '12_pinecone_rag',
  action: 'upsert',
  namespace: input.namespace,
  upserted_count: upsertResult.upsertedCount || 1,
  source: input.source,
  project: input.project,
  completedAt: new Date().toISOString()
} }];
